using System.Linq;
using System.Reflection;

var agentsAssembly = typeof(Microsoft.Agents.AI.ChatClientAgent).Assembly;
// Find extension methods
foreach(var t in agentsAssembly.GetExportedTypes().Where(t => t.Name.Contains("Extension") || t.Name.Contains("ServiceCollection")))
{
    Console.WriteLine(t.FullName);
    foreach(var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static))
        Console.WriteLine($"  static {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}
// Also check for AddAIAgent in all types
Console.WriteLine("\n--- All static methods containing 'Add' or 'Agent' ---");
foreach(var t in agentsAssembly.GetExportedTypes())
{
    foreach(var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static).Where(m => m.Name.Contains("Add") || (m.Name.Contains("Agent") && !m.Name.Contains("get_"))))
        Console.WriteLine($"  {t.Name}.{m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
}
EOF
