using System.ComponentModel;
using System.Net;
using System.Text.Json;
using System.Text.RegularExpressions;

namespace ResearchAgent;

/// <summary>
/// Tools available to the research agent for searching the web and taking notes.
/// </summary>
public sealed class ResearchTools
{
    private readonly HttpClient _httpClient;
    private readonly Dictionary<string, string> _notes = [];

    public ResearchTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1";

            var json = await _httpClient.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}\nURL: {abstractUrl}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var topicUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {topicUrl.GetString()}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try rephrasing or breaking the query into smaller parts.";
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Fetches and returns the text content of a web page at the given URL. Useful for reading articles or documentation found via search.")]
    public async Task<string> FetchWebPage(
        [Description("The full URL of the web page to fetch")] string url)
    {
        try
        {
            var html = await _httpClient.GetStringAsync(url);

            // Strip HTML tags for a rough text extraction
            var text = Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", "", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", "", RegexOptions.IgnoreCase);
            text = Regex.Replace(text, "<[^>]+>", " ");
            text = WebUtility.HtmlDecode(text);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLength = 3000;
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "... [truncated]";
            }

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    [Description("Saves a research note with a title and content. Use this to record important findings during research.")]
    public string AddNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note with key findings")] string content)
    {
        _notes[title] = content;
        return $"Note saved: '{title}' ({_notes.Count} total notes)";
    }

    [Description("Retrieves all research notes taken so far. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been taken yet.";
        }

        var entries = _notes.Select(kv => $"## {kv.Key}\n{kv.Value}");
        return string.Join("\n\n", entries);
    }
}

