            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}\nURL: {abstractUrl}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var topicUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {topicUrl.GetString()}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try rephrasing or breaking the query into smaller parts.";
