using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using ResearchAgent;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Build the tools
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var tools = new ResearchTools(httpClient);
IList<AITool> aiTools =
[
    AIFunctionFactory.Create(tools.SearchWeb),
    AIFunctionFactory.Create(tools.FetchWebPage),
    AIFunctionFactory.Create(tools.AddNote),
    AIFunctionFactory.Create(tools.GetNotes),
];

// Build the chat client via MEAI + OpenAI provider
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Build the research agent using Microsoft Agent Framework
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic the user
        provides. Follow this process:

        1. Search the web for information on the topic using multiple queries.
        2. Fetch relevant web pages to get detailed information.
        3. Take notes on your key findings using the AddNote tool.
        4. After gathering enough information (at least 3 searches), review your notes.
        5. Provide a comprehensive summary of your findings to the user.

        Be thorough but concise. Always cite your sources.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings",
    tools: aiTools);

// Get the research topic
string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? throw new InvalidOperationException("No topic provided.");
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Run the agent with iteration limits
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

